+import RuleBuilder, {BooleanOptionBuilder, DropdownOptionBuilder, ExampleBuilder, NumberOptionBuilder, OptionBuilderBase, TextAreaOptionBuilder, TextOptionBuilder} from './rule-builder';
+import dedent from 'ts-dedent';
+
+type ListStyle = 'bullet' | 'number';
+type OrderedListStyle = 'always-one' | 'increment';
+
+class AutoTocOptions implements Options {
+  listStyle: ListStyle = 'bullet';
+  bulletMarker: string = '-';
+  orderedListStyle: OrderedListStyle = 'always-one';
+  indentSize: Number = 2;
+  minLevel: Number = 2;
+  maxLevel: Number = 6;
+  title: string = '';
+  useExplicitIds: boolean = false;
+  stripFormattingInToc: boolean = false;
+  excludeHeadings: string[] = [];
+}
+
+type Heading = {
+  level: number,
+  text: string,
+  plainText: string,
+  anchor: string,
+};
+
+const startMarker = /^\\s*<!--\\s*toc\\s*-->\\s*$/i;
+const endMarker = /^\\s*<!--\\s*\\/toc\\s*-->\\s*$/i;
+const atxHeading = /^ {0,3}(#{1,6})(?:[ \	]+(.*?)|[ \	]*)$/;
+
+@RuleBuilder.register
+export default class AutoToc extends RuleBuilder<AutoTocOptions> {
+  constructor() {
+    super({
+      nameKey: 'rules.auto-toc.name',
+      descriptionKey: 'rules.auto-toc.description',
+      type: RuleType.CONTENT,
+    });
+  }
+
+  get OptionsClass(): new () => AutoTocOptions {
+    return AutoTocOptions;
+  }
+
+  apply(text: string, options: AutoTocOptions): string {
+    const newline = text.includes('\\r\
') ? '\\r\
' : '\
';
+    const lines = text.split(/\\r?\
/);
+    const protectedLines = getProtectedLines(lines);
+    const tocStart = lines.findIndex((line, index) => !protectedLines[index] && startMarker.test(line));
+
+    if (tocStart === -1) {
+      return text;
+    }
+
+    const endOffset = lines.slice(tocStart + 1).findIndex((line, index) => !protectedLines[tocStart + index + 1] && endMarker.test(line));
+    const tocEnd = endOffset === -1 ? -1 : tocStart + endOffset + 1;
+    const regionEnd = tocEnd === -1 ? tocStart : tocEnd;
+    const headings = collectHeadings(lines, protectedLines, tocStart, regionEnd, options);
+    const tocLines = buildToc(lines[tocStart], tocEnd === -1 ? '<!-- /toc -->' : lines[tocEnd], headings, options);
+
+    return [...lines.slice(0, tocStart), ...tocLines, ...lines.slice(tocEnd === -1 ? tocStart + 1 : tocEnd + 1)].join(newline);
+  }
+
+  get exampleBuilders(): ExampleBuilder<AutoTocOptions>[] {
+    return [
+      new ExampleBuilder({
+        description: 'Generates a table of contents from ATX headings',
+        before: dedent`
+          <!-- toc -->
+
+          ## First section
+          ### A child
+          ## Last section
+        `,
+        after: dedent`
+          <!-- toc -->
+
+          - [First section](#first-section)
+            - [A child](#a-child)
+          - [Last section](#last-section)
+
+          <!-- /toc -->
+
+          ## First section
+          ### A child
+          ## Last section
+        `,
+      }),
+    ];
+  }
+
+  get optionBuilders(): OptionBuilderBase<AutoTocOptions>[] {
+    return [
+      new DropdownOptionBuilder({
+        OptionsClass: AutoTocOptions,
+        nameKey: 'rules.auto-toc.list-style.name',
+        descriptionKey: 'rules.auto-toc.list-style.description',
+        optionsKey: 'listStyle',
+        records: [{value: 'bullet', description: 'Use bullet list items.'}, {value: 'number', description: 'Use ordered list items.'}],
+      }),
+      new TextOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.bullet-marker.name', descriptionKey: 'rules.auto-toc.bullet-marker.description', optionsKey: 'bulletMarker'}),
+      new DropdownOptionBuilder({
+        OptionsClass: AutoTocOptions,
+        nameKey: 'rules.auto-toc.ordered-list-style.name',
+        descriptionKey: 'rules.auto-toc.ordered-list-style.description',
+        optionsKey: 'orderedListStyle',
+        records: [{value: 'always-one', description: 'Use 1 for every item.'}, {value: 'increment', description: 'Increment across all items.'}],
+      }),
+      new NumberOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.indent-size.name', descriptionKey: 'rules.auto-toc.indent-size.description', optionsKey: 'indentSize'}),
+      new NumberOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.min-level.name', descriptionKey: 'rules.auto-toc.min-level.description', optionsKey: 'minLevel'}),
+      new NumberOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.max-level.name', descriptionKey: 'rules.auto-toc.max-level.description', optionsKey: 'maxLevel'}),
+      new TextOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.title.name', descriptionKey: 'rules.auto-toc.title.description', optionsKey: 'title'}),
+      new BooleanOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.use-explicit-ids.name', descriptionKey: 'rules.auto-toc.use-explicit-ids.description', optionsKey: 'useExplicitIds'}),
+      new BooleanOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.strip-formatting-in-toc.name', descriptionKey: 'rules.auto-toc.strip-formatting-in-toc.description', optionsKey: 'stripFormattingInToc'}),
+      new TextAreaOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.exclude-headings.name', descriptionKey: 'rules.auto-toc.exclude-headings.description', optionsKey: 'excludeHeadings'}),
+    ];
+  }
+}
+
+function getProtectedLines(lines: string[]): boolean[] {
+  const result = new Array<boolean>(lines.length).fill(false);
+  let inYaml = lines[0]?.trim() === '---';
+  let fence: string = null;
+  let inMath = false;
+
+  for (let index = 0; index < lines.length; index++) {
+    const line = lines[index];
+    if (inYaml) {
+      result[index] = true;
+      if (index > 0 && /^(---|\\.\\.\\.)\\s*$/.test(line)) inYaml = false;
+      continue;
+    }
+    if (fence) {
+      result[index] = true;
+      if (new RegExp(`^ {0,3}${fence}{3,}`).test(line)) fence = null;
+      continue;
+    }
+    if (inMath) {
+      result[index] = true;
+      if (/^\\s*\\$\\$\\s*$/.test(line)) inMath = false;
+      continue;
+    }
+
+    const fenceMatch = line.match(/^ {0,3}(`{3,}|~{3,})/);
+    if (fenceMatch) {
+      result[index] = true;
+      fence = fenceMatch[1][0];
+    } else if (/^\\s*\\$\\$\\s*$/.test(line)) {
+      result[index] = true;
+      inMath = true;
+    }
+  }
+  return result;
+}
+
+function collectHeadings(lines: string[], protectedLines: boolean[], tocStart: number, tocEnd: number, options: AutoTocOptions): Heading[] {
+  const headings: Heading[] = [];
+  const anchors = new Map<string, number>();
+  for (let index = 0; index < lines.length; index++) {
+    if (protectedLines[index] || (index >= tocStart && index <= tocEnd)) continue;
+    const match = lines[index].match(atxHeading);
+    if (!match) continue;
+
+    const level = match[1].length;
+    const withoutClosingHashes = match[2].replace(/[ \	]+#+[ \	]*$/, '');
+    const explicitId = withoutClosingHashes.match(/\\s*\\{#([^}]+)\\}\\s*$/);
+    const displayText = explicitId ? withoutClosingHashes.slice(0, explicitId.index).trimEnd() : withoutClosingHashes;
+    const resolvedText = resolveLinksAndImages(displayText).trim();
+    const plainText = stripFormatting(resolvedText).trim();
+    const baseAnchor = options.useExplicitIds && explicitId ? explicitId[1] : plainText;
+    const anchor = dedupeAnchor(makeAnchor(baseAnchor), anchors);
+    if (level >= Number(options.minLevel) && level <= Number(options.maxLevel) && !isExcluded(resolvedText, plainText, options.excludeHeadings)) {
+      headings.push({level, text: options.stripFormattingInToc ? plainText : resolvedText, plainText, anchor});
+    }
+  }
+  return headings;
+}
+
+function buildToc(start: string, end: string, headings: Heading[], options: AutoTocOptions): string[] {
+  const lines = [start, ''];
+  if (options.title) lines.push(options.title, '');
+  const minLevel = Number(options.minLevel);
+  headings.forEach((heading, index) => {
+    const indent = ' '.repeat(Math.max(0, heading.level - minLevel) * Number(options.indentSize));
+    const marker = options.listStyle === 'number' ? `${options.orderedListStyle === 'increment' ? index + 1 : 1}.` : options.bulletMarker;
+    lines.push(`${indent}${marker} [${heading.text}](#${heading.anchor})`);
+  });
+  if (lines[lines.length - 1] !== '') lines.push('');
+  lines.push(end, '');
+  return lines;
+}
+
+function resolveLinksAndImages(text: string): string {
+  return text
+      .replace(/!\\[\\[[^\\]\
]*(?:\\]\\])?/g, '')
+      .replace(/!\\[[^\\]]*\\]\\([^\
)]*\\)/g, '')
+      .replace(/\\[\\[([^\\]|\
]+)(?:\\|([^\\]\
]+))?\\]\\]/g, (_, target: string, display: string) => display ?? target)
+      .replace(/(?<!!)(?<!\\!)\\[([^\\]]*)\\]\\([^\
)]*\\)/g, '$1');
+}
+
+function stripFormatting(text: string): string {
+  return text.replace(/\\\\(.)/g, '$1').replace(/(\\*\\*|__|~~|\\*|_|`)/g, '');
+}
+
+function makeAnchor(text: string): string {
+  return text.toLowerCase().replace(/\\s+/g, '-').replace(/[^a-z0-9-_]/g, '').replace(/-+/g, '-').replace(/^-+|-+$/g, '');
+}
+
+function dedupeAnchor(baseAnchor: string, anchors: Map<string, number>): string {
+  const count = anchors.get(baseAnchor) ?? 0;
+  anchors.set(baseAnchor, count + 1);
+  return count === 0 ? baseAnchor : `${baseAnchor}-${count}`;
+}
+
+function isExcluded(text: string, plainText: string, exclusions: string[]): boolean {
+  return exclusions.some((exclusion) => {
+    if (exclusion.startsWith('/') && exclusion.endsWith('/') && exclusion.length > 2) {
+      try {
+        const expression = new RegExp(exclusion.slice(1, -1), 'i');
+        return expression.test(text) || expression.test(plainText);
+      } catch (_) {
+        // An invalid regular expression is treated as a literal heading.
+      }
+    }
+    return exclusion.toLowerCase() === text.toLowerCase() || exclusion.toLowerCase() === plainText.toLowerCase();
+  });
+}
